use std::collections::HashMap;

struct Node<K, V> {
    key: K,
    value: V,
    prev: Option<*mut Node<K, V>>,
    next: Option<*mut Node<K, V>>,
}

pub struct LruCache<K, V> {
    capacity: usize,
    map: HashMap<K, Box<Node<K, V>>>,
    head: Option<*mut Node<K, V>>,  // most recent
    tail: Option<*mut Node<K, V>>,  // least recent
}

fn move_to_front(&mut self, node: *mut Node<K, V>) {
    unsafe {
        // Remove from current position
        if let Some(prev) = (*node).prev {
            (*prev).next = (*node).next;
        }
        if let Some(next) = (*node).next {
            (*next).prev = (*node).prev;
        }
        if self.tail == Some(node) {
            self.tail = (*node).prev;
        }
        // Add to front
        (*node).prev = None;
        (*node).next = self.head;
        if let Some(head) = self.head {
            (*head).prev = Some(node);
        }
        self.head = Some(node);
    }
}
